// Flare version-check probe + service-worker plumbing (used by VersionCheckService).
//
// The service-worker FILE (service-worker.js, generated by the Blazor PWA tooling) is the app's, but
// the boilerplate around it - registering it, reading the deployed version, applying a waiting worker
// - lives here so apps don't re-implement it. The deployed version is taken from the Blazor PWA assets
// manifest (service-worker-assets.js), whose `version` hash changes on every published build.

let _reg = null;

// Register the app's service worker (optional - the service calls this when ServiceWorkerPath is set).
export async function register(path) {
    if (!('serviceWorker' in navigator)) return;
    try {
        _reg = await navigator.serviceWorker.register(path || 'service-worker.js', { updateViaCache: 'none' });
    } catch (e) {
        console.error('Service worker registration failed', e);
    }
}

async function getRegistration() {
    if (_reg) return _reg;
    if (!('serviceWorker' in navigator)) return null;
    try { return await navigator.serviceWorker.getRegistration(); } catch { return null; }
}

async function readDeployedVersion() {
    try {
        // no-store so we always hit the server, not the HTTP/SW cache.
        const res = await fetch('service-worker-assets.js', { cache: 'no-store' });
        if (!res.ok) return null;
        const text = await res.text();
        const m = text.match(/self\.assetsManifest\s*=\s*\{[\s\S]*?["']version["']\s*:\s*["']([^"']+)["']/);
        return m ? m[1] : null;
    } catch {
        return null;
    }
}

// Returns the currently deployed app version (assets-manifest hash), or null if it can't be read
// (offline, dev server without the manifest, etc.). Called once per poll tick by the service. Also
// nudges the browser to re-check the server for a newer worker so applyUpdate has something to apply.
export async function check() {
    const reg = await getRegistration();
    if (reg) { try { await reg.update(); } catch { /* ignore */ } }
    return await readDeployedVersion();
}

// Activate the waiting worker (if any) and reload so the page runs the new version. Blazor's default
// SW does not call clients.claim(), so we reload explicitly rather than rely on 'controllerchange'.
export async function applyUpdate() {
    const reg = await getRegistration();
    if (reg) { try { await reg.update(); } catch { /* ignore */ } }
    const waiting = reg && reg.waiting;
    if (!waiting) { location.reload(); return; }
    waiting.addEventListener('statechange', () => {
        if (waiting.state === 'activated') location.reload();
    });
    waiting.postMessage('skipWaiting');
    setTimeout(() => location.reload(), 3000); // fallback if the statechange event is missed
}
